const rows = $input.all().map(item => item.json);

if (
  rows.length === 0 ||
  rows.every(row => Object.keys(row).length === 0)
) {
  return [{
    json: {
      message: "No matching hospital records were found for that question."
    }
  }];
}

let message = "Here are the results I found:\n\n";

rows.slice(0, 10).forEach((row, index) => {
  let block = `${index + 1}. ${row.facility_name || "Unknown Hospital"}\n`;

  if (row.facility_id) {
    block += `   Facility ID: ${row.facility_id}\n`;
  }

  if (row.state) {
    block += `   State: ${row.state}\n`;
  }

  if (row.hospital_overall_rating) {
    block += `   Overall Rating: ${row.hospital_overall_rating}\n`;
  }

  if (row.emergency_services) {
    block += `   Emergency Services: ${row.emergency_services}\n`;
  }

  if (row.hospital_type) {
    block += `   Hospital Type: ${row.hospital_type}\n`;
  }

  if (row.hospital_ownership) {
    block += `   Ownership: ${row.hospital_ownership}\n`;
  }

  if (row.measure_name) {
    block += `   Measure: ${row.measure_name}\n`;
  }

  if (row.maternal_measure) {
    block += `   Maternal Measure: ${row.maternal_measure}\n`;
  }

  if (row.complication_measure) {
    block += `   Complication Measure: ${row.complication_measure}\n`;
  }

  if (row.readmission_measure) {
    block += `   Readmission Measure: ${row.readmission_measure}\n`;
  }

  if (row.condition) {
    block += `   Condition: ${row.condition}\n`;
  }

  if (row.score) {
    block += `   Score: ${row.score}\n`;
  }

  if (row.sample) {
    block += `   Sample: ${row.sample}\n`;
  }

  if (row.compared_to_national) {
    block += `   Compared to National: ${row.compared_to_national}\n`;
  }

  if (row.number_of_patients_returned) {
    block += `   Patients Returned: ${row.number_of_patients_returned}\n`;
  }

  const measureText = [
    row.measure_name,
    row.maternal_measure,
    row.complication_measure,
    row.readmission_measure,
    row.condition
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();

  if (measureText) {
    block += "\n   Insight: ";

    if (measureText.includes("readmission") || measureText.includes("return")) {
      block += "Lower readmission or return-visit scores generally indicate better performance.\n";
    } else if (measureText.includes("death") || measureText.includes("mortality")) {
      block += "Lower mortality scores generally indicate better outcomes.\n";
    } else if (
      measureText.includes("complication") ||
      measureText.includes("infection") ||
      measureText.includes("respiratory failure") ||
      measureText.includes("patient safety") ||
      measureText.includes("adverse events") ||
      measureText.includes("fall") ||
      measureText.includes("fracture") ||
      measureText.includes("puncture") ||
      measureText.includes("laceration") ||
      measureText.includes("pneumothorax") ||
      measureText.includes("embolism") ||
      measureText.includes("thrombosis") ||
      measureText.includes("hemorrhage") ||
      measureText.includes("hematoma")
    ) {
      block += "Lower complication-related scores generally indicate safer care.\n";
    } else if (measureText.includes("maternal")) {
      block += "Maternal measures indicate whether the hospital reports maternal health-related quality information.\n";
    } else {
      block += "This result matches the requested hospital quality criteria.\n";
    }
  } else if (row.hospital_overall_rating) {
    block += `\n   Insight: Hospital overall rating is ${row.hospital_overall_rating}/5.\n`;
  }

  const sources = [];

  if (
    row.hospital_overall_rating ||
    row.emergency_services ||
    row.hospital_type ||
    row.hospital_ownership
  ) {
    sources.push("hospital_general_information");
  }

  if (
    row.measure_name &&
    (
      row.measure_name.toLowerCase().includes("readmission") ||
      row.measure_name.toLowerCase().includes("return")
    )
  ) {
    sources.push("unplanned_hospital_visits_hospital");
  }

  if (
    row.readmission_measure
  ) {
    sources.push("unplanned_hospital_visits_hospital");
  }

  if (
    row.measure_name &&
    (
      row.measure_name.toLowerCase().includes("death") ||
      row.measure_name.toLowerCase().includes("mortality") ||
      row.measure_name.toLowerCase().includes("complication") ||
      row.measure_name.toLowerCase().includes("infection") ||
      row.measure_name.toLowerCase().includes("fracture") ||
      row.measure_name.toLowerCase().includes("embolism") ||
      row.measure_name.toLowerCase().includes("thrombosis") ||
      row.measure_name.toLowerCase().includes("puncture") ||
      row.measure_name.toLowerCase().includes("laceration") ||
      row.measure_name.toLowerCase().includes("pneumothorax") ||
      row.measure_name.toLowerCase().includes("hemorrhage") ||
      row.measure_name.toLowerCase().includes("hematoma") ||
      row.measure_name.toLowerCase().includes("patient safety") ||
      row.measure_name.toLowerCase().includes("adverse events")
    )
  ) {
    sources.push("complications_and_deaths_hospital");
  }

  if (row.complication_measure) {
    sources.push("complications_and_deaths_hospital");
  }

  if (
    row.maternal_measure ||
    (
      row.measure_name &&
      row.measure_name.toLowerCase().includes("maternal")
    )
  ) {
    sources.push("maternal_health_hospital");
  }

  if (row.condition) {
    sources.push("timely_and_effective_care_hospital");
  }

  if (sources.length > 0) {
    block += `\n   Source: ${[...new Set(sources)].join(" + ")}\n`;
  }

  message += block + "\n";
});

return [{
  json: {
    message
  }
}];

return [{
  json: {
    message: "I am unable to answer that. I can only provide insights based on the hospital analytics datasets."
  }
}];

const rows = $input.all().map(item => item.json);

const chartData = rows
  .slice(0,10)
  .map(r => ({
    hospital: r.facility_name,
    score: Number(r.score)
  }))
  .filter(r => !isNaN(r.score));

return [{
  json: {
    labels: chartData.map(x => x.hospital),
    values: chartData.map(x => x.score)
  }
}];

